INSERT INTO "public"."analyses" ("id", "created_at", "analysis_id", "patient_name", "document_type", "resume_simple", "elements_cles", "conseils_patient", "patient_age", "patient_sex", "doc_filename", "alerte_medecin", "patient_id", "questions_possibles", "timestamp", "extracted_text") VALUES (14, '2026-04-08 15:00:44.032537+00', null, 'Bilim Bilim MOMBO ', 'résultats_analyses', 'Les résultats des analyses médicales montrent les résultats d''un test de dépistage de la tuberculose. Le test Quantiferon-TB Gold Plus a été réalisé et les résultats sont négatifs, ce qui signifie que le patient n''a pas d''infection à Mycobacterium tuberculosis détectée par ce test. Cependant, il est important de noter que ce test n''est pas définitif pour le diagnostic de la tuberculose.', '[{"norme":"Négatif","statut":"normal","valeur":"Négatif","terme_medical":"Timo''n négatif (TN)","explication_simple":"Le résultat du test est négatif, ce qui signifie que le patient n''a pas d''infection détectée"},{"norme":"Non précisée","statut":"info","valeur":"0.08","terme_medical":"AOTB CD4-TN","explication_simple":"Résultat d''un test spécifique pour la tuberculose"},{"norme":"Non précisée","statut":"info","valeur":"0.02","terme_medical":"Ag Te CD4/CD8.TN","explication_simple":"Résultat d''un test spécifique pour la tuberculose"},{"norme":"Non précisée","statut":"info","valeur":"10","terme_medical":"Témoin positif.TN","explication_simple":"Contrôle positif pour le test"}]', '["Consultez votre médecin pour discuter des résultats et de leur signification","Si vous avez des symptômes de tuberculose, consultez immédiatement un médecin"]', '12', 'homme', 'Capture d''écran 2026-04-08 160739.png', '{"raison":"Résultats négatifs, pas de valeurs critiques","urgence":"faible","necessaire":false}', '04c0e7f4-b367-4d7d-a8e5-c2fc66233dc8', '["Qu''est-ce que le test Quantiferon-TB Gold Plus ?","Que signifie un résultat négatif ?","Puis-je développer une tuberculose même avec un résultat négatif ?"]', '2026-04-08 15:00:43.886+00', null), (15, '2026-04-09 07:41:25.686494+00', null, 'Bilim Bilim MOMBO ', 'résultats_analyses', 'Ce document présente les résultats d''analyses médicales pour le patient KOFFI BAKAN ERIC, comprenant des tests d''hématologie et de formule leucocytaire. Les résultats montrent certaines valeurs qui pourraient nécessiter une attention particulière.', '[{"norme":"4-11 x10^9/L","statut":"normal","valeur":"7,73","terme_medical":"Leucocytes","explication_simple":"Les leucocytes sont des cellules sanguines qui aident à lutter contre les infections"},{"norme":"13,5-17,5 x10^12/L (hommes), 12-16 x10^12/L (femmes)","statut":"bas","valeur":"12,1","terme_medical":"Hématies","explication_simple":"Les hématies sont des cellules sanguines qui transportent l''oxygène"},{"norme":"130-170 g/L (hommes), 120-150 g/L (femmes)","statut":"bas","valeur":"39","terme_medical":"Hémoglobine","explication_simple":"L''hémoglobine est une protéine dans les hématies qui transporte l''oxygène"}]', '["Prenez rendez-vous avec votre médecin pour discuter des résultats","Suivez les instructions de votre médecin pour tout traitement ou examen supplémentaire"]', '12', 'homme', 'thumb_1200_1698.png', '{"raison":"Certaines valeurs sont en dehors des normes, notamment les hématies et l''hémoglobine","urgence":"modérée","necessaire":true}', '04c0e7f4-b367-4d7d-a8e5-c2fc66233dc8', '["Qu''est-ce que signifient ces résultats pour ma santé ?","Dois-je suivre un traitement ou subir d''autres examens ?","Comment puis-je améliorer mes résultats sanguins ?"]', '2026-04-09 07:41:26.048+00', null), (16, '2026-04-09 09:09:50.1999+00', null, 'yayaalonso488', 'résultats_analyses', 'Ce document présente les résultats d''analyses médicales pour M. KOFFI BAKAN ERIC, notamment des tests d''hématologie. Les résultats montrent des valeurs pour les leucocytes, hématies, hémoglobine, hématocrite, et d''autres paramètres sanguins.', '[{"norme":"4 000 à 10 000 par microlitre","statut":"info","valeur":"12h00","te